queries.sphinxql:
CREATE TABLE uuid_rt ( id uuid, title text indexed, tag string, price int ) rt_mem_limit='12M';
CREATE CLUSTER test;
ALTER CLUSTER test ADD uuid_rt;
INSERT INTO test:uuid_rt ( id, title, tag, price ) VALUES ( '550e8400-e29b-41d4-a716-446655441000', 'seed document', 'seed', 10 );
SELECT id, tag, price FROM test:uuid_rt ORDER BY id ASC;

INSERT INTO test:uuid_rt ( id, title, tag, price ) VALUES ( '550e8400-e29b-41d4-a716-446655441001', 'node1 insert', 'node1', 20 );
UPDATE test:uuid_rt SET price=21, tag='node1-updated' WHERE id='550e8400-e29b-41d4-a716-446655441001';
SELECT id, tag, price FROM test:uuid_rt ORDER BY id ASC;

REPLACE INTO test:uuid_rt ( id, title, tag, price ) VALUES ( '550e8400-e29b-41d4-a716-446655441000', 'seed replaced', 'replaced', 11 );
DELETE FROM test:uuid_rt WHERE id='550e8400-e29b-41d4-a716-446655441001';
SELECT id, tag, price FROM test:uuid_rt ORDER BY id ASC;

ALTER CLUSTER test DROP uuid_rt;
DROP TABLE uuid_rt;
DELETE CLUSTER test;
